_D='25/07/2023'
_C='SSI'
_B='31/07/2023'
_A='data'
from pandas import json_normalize
import pandas as pd,json,time
from typing import Union
from ssi_fc_data import fc_md_client,model
from ssi_fc_data.fc_md_client import MarketDataClient
class StockData:
	def __init__(A,client,config):A.client=client;A.config=config
	def listing(A,market='HOSE',page=1,size=1000):'\n        Lấy danh sách chứng khoán.\n\n        Args:\n            market (str): Tên sàn giao dịch: HOSE, HNX, UPCOM. Mặc định là HOSE.\n            page (int): Số trang. Mặc định là 1.\n            size (int): Kích thước trang. Mặc định là 1000.\n\n        Returns:\n            pd.DataFrame: DataFrame chứa danh sách chứng khoán.\n        ';C=model.securities(market,page,size);B=A.client.securities(A.config,C);print('Tổng số bản ghi: '+str(B['totalRecord']));return pd.DataFrame(B[_A])
	def details(B,symbol='ACB',market='HOSE',page=1,size=100):'\n        Lấy chi tiết của mã chứng khoán.\n\n        Args:\n            symbol (str): Mã chứng khoán. Mặc định là ACB.\n            market (str): Tên sàn giao dịch. Mặc định là HOSE.\n            page (int): Số trang. Mặc định là 1.\n            size (int): Kích thước trang. Mặc định là 100.\n\n        Returns:\n            pd.DataFrame: DataFrame chứa chi tiết chứng khoán.\n        ';D='ReportDate';E=model.securities_details(market,symbol,page,size);C=B.client.securities_details(B.config,E)[_A];A=json_normalize(C[0]['RepeatedInfo']);A[D]=C[0][D];A=A.dropna(axis=1,how='all');return A
	def daily_ohlc(B,symbol=_C,start='01/07/2023',end=_B,ascending=True,page=1,size=1000):'\n        Lấy dữ liệu OHLC hàng ngày.\n\n        Args:\n            symbol (str): Mã chứng khoán. Mặc định là SSI.\n            start (str): Ngày bắt đầu (dd/MM/yyyy). Mặc định là 01/07/2023.\n            end (str): Ngày kết thúc (dd/MM/yyyy). Mặc định là 31/07/2023.\n            ascending (bool): Sắp xếp tăng dần hoặc giảm dần. Mặc định là True.\n            page (int): Số trang. Mặc định là 1.\n            size (int): Kích thước trang. Mặc định là 1000.\n\n        Returns:\n            pd.DataFrame: DataFrame chứa dữ liệu OHLC hàng ngày.\n        ';C=model.daily_ohlc(symbol,start,end,page,size,ascending);D=B.client.daily_ohlc(B.config,C)[_A];A=json_normalize(D);A=A.drop(columns=['Time']);return A
	def intraday_ohlc(A,symbol=_C,start=_D,end=_B,page=1,size=1000,ascending=True,resolution=1):'\n        Lấy dữ liệu OHLC trong ngày.\n\n        Args:\n            symbol (str): Mã chứng khoán. Mặc định là SSI.\n            start (str): Ngày bắt đầu (dd/MM/yyyy). Mặc định là 25/07/2023.\n            end (str): Ngày kết thúc (dd/MM/yyyy). Mặc định là 31/07/2023.\n            page (int): Số trang. Mặc định là 1.\n            size (int): Kích thước trang. Mặc định là 1000.\n            ascending (bool): Sắp xếp tăng dần hoặc giảm dần. Mặc định là True.\n            resolution (int): Nhóm theo phút. Mặc định là 1.\n\n        Returns:\n            pd.DataFrame: DataFrame chứa dữ liệu OHLC trong ngày.\n        ';B=model.intraday_ohlc(symbol,start,end,page,size,ascending,resolution);C=A.client.intraday_ohlc(A.config,B);return json_normalize(C[_A])
	def daily_price(A,symbol=_C,start=_D,end=_B,page=1,size=1000,market=''):'\n        Lấy giá cổ phiếu hàng ngày.\n\n        Args:\n            symbol (str): Mã chứng khoán. Mặc định là SSI.\n            start (str): Ngày bắt đầu (dd/MM/yyyy). Mặc định là 25/07/2023.\n            end (str): Ngày kết thúc (dd/MM/yyyy). Mặc định là 31/07/2023.\n            page (int): Số trang. Mặc định là 1.\n            size (int): Kích thước trang. Mặc định là 1000.\n            market (str): Thị trường cho mã chứng khoán. Mặc định là chuỗi rỗng.\n\n        Returns:\n            pd.DataFrame: DataFrame chứa giá cổ phiếu hàng ngày.\n        ';B=model.daily_stock_price(symbol,start,end,page,size,market);C=A.client.daily_stock_price(A.config,B)[_A];return json_normalize(C)
class IndexData:
	def __init__(A,client,config):A.client=client;A.config=config
	def listing(A,exchange='',page=1,size=100):'\n        Lấy danh sách mã và tên các chỉ số.\n\n        Args:\n            exchange (str, optional): Tên sàn giao dịch. Nếu không có giá trị sẽ trả về tất cả các sàn.\n\n        Returns:\n            pd.DataFrame: DataFrame chứa danh sách chỉ số.\n        ';B=model.index_list(exchange,page,size);C=A.client.index_list(A.config,B)[_A];return json_normalize(C)
	def component(C,index='VN30',page=1,size=100):'\n        Lấy danh sách mã chứng khoán trong một chỉ số.\n\n        Args:\n            index (str): Mã chỉ số. Mặc định là VN30.\n            page (int): Số trang. Mặc định là 1.\n            size (int): Kích thước trang. Mặc định là 1000.\n\n        Returns:\n            pd.DataFrame: DataFrame chứa danh sách mã chứng khoán.\n        ';D=model.index_components(index,page,size);A=C.client.index_components(C.config,D)[_A][0];E=A['IndexCode'];F=A['Exchange'];G=A['TotalSymbolNo'];print(f"Chỉ số: {E} - {F}. Tổng số {G} mã chứng khoán");B=json_normalize(A['IndexComponent']);B=B.drop(columns=['Isin']);return B
	def daily_ohlc(B,index='VN30',start=_D,end=_B,page=1,size=1000,orderBy='Tradingdate',order='desc',request_id=''):'\n        Trả về dữ liệu chỉ số hàng ngày.\n\n        Args:\n            index (str): Tên chỉ số. Mặc định là VN30.\n            start (str): Ngày bắt đầu (dd/MM/yyyy). Mặc định là 25/07/2023.\n            end (str): Ngày kết thúc (dd/MM/yyyy). Mặc định là 31/07/2023.\n            page (int): Số trang. Mặc định là 1.\n            size (int): Kích thước trang. Mặc định là 1000.\n            orderBy (str): Cột sắp xếp. Mặc định là Tradingdate.\n            order (str): Kiểu sắp xếp. Mặc định là giảm dần (desc).\n            request_id (str): ID yêu cầu. Mặc định là chuỗi rỗng.\n\n        Returns:\n            pd.DataFrame: DataFrame chứa dữ liệu chỉ số hàng ngày.\n        ';C=model.daily_index(request_id,index,start,end,page,size,orderBy,order);D=B.client.daily_index(B.config,C)[_A];A=json_normalize(D);A=A.dropna(axis=1,how='all');return A
class Config:
	def __init__(A,consumer_id,consumer_secret,access_token=None):"\n        Khởi tạo đối tượng cấu hình chứa thông tin cần thiết để kết nối tới API SSI Fast Connect.\n\n        Tham số:\n            - auth_type (str): Loại xác thực (ví dụ: 'Bearer').\n            - consumerID (str): ID người dùng.\n            - consumerSecret (str): Mật khẩu người dùng.\n            - access_token (str): Token tạo ra từ thông tin đăng nhập, sinh ra bằng cách gọi hàm get_token.\n\n        Thuộc tính:\n            - auth_type (str): Loại xác thực.\n            - consumerID (str): ID người dùng.\n            - consumerSecret (str): Mật khẩu người dùng.\n            - access_jwt (str): Mã thông báo JWT truy cập.\n            - url (str): URL của API dữ liệu thị trường.\n            - stream_url (str): URL của API dữ liệu dòng.\n        ";B='https://fc-data.ssi.com.vn/';A.consumerID=consumer_id;A.consumerSecret=consumer_secret;A.auth_type='Bearer';A.url=B;A.stream_url=B;A.access_jwt=access_token
def get_token(config):A=config;B=fc_md_client.MarketDataClient(A);C=B.access_token(model.accessToken(A.consumerID,A.consumerSecret));return C
class FCData:
	def __init__(A,config):'\n        Khởi tạo đối tượng để truy xuất dữ liệu từ SSI Fast Connect Data API.\n\n        Tham số:\n            - config (object): Đối tượng cấu hình chứa các thông tin cần thiết để kết nối tới API.\n\n        Thuộc tính:\n            - config (object): Đối tượng cấu hình được truyền vào.\n            - client (MarketDataClient): Đối tượng khách hàng để tương tác với API dữ liệu thị trường.\n            - stock (StockData): Đối tượng để truy xuất dữ liệu chứng khoán.\n            - index (IndexData): Đối tượng để truy xuất dữ liệu chỉ số.\n        ';B=config;A.config=B;A.client=fc_md_client.MarketDataClient(B);A.stock=StockData(A.client,B);A.index=IndexData(A.client,B)